import re
import unicodedata
from dataclasses import dataclass

@dataclass
class InputScanResult:
    blocked: bool
    risk_score: float   # 0.0 = safe, 1.0 = certain injection
    matched_patterns: list[str]
    surface: str        # "user_input" | "rag_chunk" | "tool_result"

# Normalize Unicode before scanning (blocks lookalike obfuscation)
def normalize(text: str) -> str:
    return unicodedata.normalize("NFKC", text)

_PATTERNS = [
    (re.compile(r'(?i)ignore\s+(all\s+)?(previous|prior)\s+instructions'), "ignore_previous", 0.95),
    (re.compile(r'(?i)you\s+are\s+now\s+[a-z ]{3,30}without\s+restrictions'), "persona_override", 0.90),
    (re.compile(r'(?i)(reveal|print|show|repeat)\s+(your\s+)?(system\s+)?prompt'), "prompt_extract", 0.85),
    (re.compile(r'(?i)(jailbreak|DAN|do anything now|developer mode)'), "jailbreak", 0.75),
    (re.compile(r'(?i)fetch\s+https?://[a-z0-9.-]+\.[a-z]{2,}/\?\w+='), "url_exfil", 0.85),
]

def scan_input(text: str, surface: str) -> InputScanResult:
    text_norm = normalize(text)
    max_score, matched = 0.0, []
    for pat, name, score in _PATTERNS:
        if pat.search(text_norm):
            max_score = max(max_score, score)
            matched.append(name)
    return InputScanResult(
        blocked=max_score >= 0.80,
        risk_score=max_score,
        matched_patterns=matched,
        surface=surface,
    )

import re
import hashlib
from dataclasses import dataclass

@dataclass
class DLPResult:
    clean_response: str
    violations: list[str]
    redacted_count: int

_DLP_RULES = [
    (re.compile(r'[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}'), "email"),
    (re.compile(r'sk-[a-zA-Z0-9]{32,}'), "api_key"),
    (re.compile(r'\b\d{3}[-.]?\d{2}[-.]?\d{4}\b'), "ssn"),
    (re.compile(r'(?i)(password|secret|token)\s*[:=]\s*\S+'), "credential"),
]

def dlp_scan_output(response: str, system_prompt: str) -> DLPResult:
    violations, redacted = [], 0
    # PII and credential patterns
    for pat, name in _DLP_RULES:
        if pat.search(response):
            violations.append(name)
            response = pat.sub(f"[{name.upper()}_REDACTED]", response)
            redacted += 1
    # System prompt leak detection (n-gram overlap)
    sp_grams = {system_prompt[i:i+32] for i in range(0, len(system_prompt)-32, 8)}
    resp_grams = {response[i:i+32] for i in range(0, len(response)-32, 8)}
    if len(sp_grams & resp_grams) >= 3:
        violations.append("system_prompt_leak")
        response = "[RESPONSE BLOCKED: potential system prompt disclosure]"
    return DLPResult(clean_response=response, violations=violations, redacted_count=redacted)
